-- Luke Chapter 11
-- Theme: Prayer, Spiritual Conflict, and the Accountability of Light
-- 54 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 11,
  'Luke 11 opens with Jesus praying — as he does at every great turning point in Luke''s Gospel — and his disciples'' earnest request: "Lord, teach us to pray" (v.1). The model prayer he gives (vv.2-4) is shorter than Matthew''s version but equally comprehensive, addressing God''s name, kingdom, provision, forgiveness, and deliverance. The parable of the friend at midnight (vv.5-8) introduces shamelessness (anaideia) as the posture of persistent prayer, followed by the triple promise of Ask-Seek-Knock (vv.9-13), which climaxes not in material provision but in the gift of the Holy Spirit — the supreme answer to prayer.' ||
  'The Beelzebub controversy (vv.14-26) forms the chapter''s theological battlefield. Jesus demonstrates by logic that his exorcisms cannot come from Satan — a divided kingdom falls — and by typology that his works fulfil the "finger of God" motif of the Exodus (v.20). The parable of the strong man overcome (vv.21-22) portrays the cross as the cosmic victory over the armed keeper of souls. The sobering warning about the returning unclean spirit (vv.24-26) applies to Israel''s spiritual condition: swept clean by John''s ministry but not filled with the Spirit.' ||
  'The sign of Jonah (vv.29-32) is Jesus''s only concession to sign-seekers, but given as a rebuke rather than a gift. The queen of Sheba and the Ninevites will condemn this generation because they responded to lesser messengers. The lamp and eye sayings (vv.33-36) press for undivided spiritual vision: only the "single eye" (haploūs — clear, generous, wholehearted) receives the full light of Christ. The chapter closes with a devastating series of seven woes against the Pharisees and lawyers (vv.37-54) — the most extensive public denunciation in Luke — for straining out external religion while ignoring justice, love, and the key of knowledge.' ||
  'The setting of the woes in the Pharisee''s dining room (v.37) replicates the dinner scene of chapter 7. The seven woes (three against Pharisees: vv.42-44; three against lawyers: vv.46-52; with the blood-guilt summary vv.49-51) build to the indictment that they have "taken away the key of knowledge" (v.52). The chapter ends with the scribes and Pharisees laying wait to catch something out of Jesus''s mouth — the hostility that will eventually produce the crucifixion.',
  'Prayer, Spiritual Conflict, and the Accountability of Light',
  'προσεύχομαι (proseuchomai)',
  'proseuchomai means to pray, to address God in petition and worship, derived from pros (toward) + euchomai (to wish, to vow). Luke uses this verb more than any other Synoptic writer, consistently emphasizing Jesus''s own prayer life as the foundational model for discipleship. In Luke 11, prayer is the chapter''s architectural key: it opens with the disciples'' request to be taught to pray (v.1), and all subsequent teaching on asking, seeking, and knocking flows from this primal posture of dependent communion with the Father.',
  '["The Lord''s Prayer: A Model for All Communion with God (vv.1-4)","The Friend at Midnight: Shameless Persistence in Prayer (vv.5-13)","The Beelzebub Controversy: The Finger of God and the Bound Strong Man (vv.14-28)","The Sign of Jonah: Greater Than Solomon and Jonah (vv.29-36)","Seven Woes: The Corruption of Religion and the Blood of the Prophets (vv.37-54)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And it came to pass, that, as he was praying in a certain place, when he ceased, one of his disciples said unto him, Lord, teach us to pray, as John also taught his disciples.', 'Καὶ ἐγένετο ἐν τῷ εἶναι αὐτὸν ἐν τόπῳ τινὶ προσευχόμενον, ὡς ἐπαύσατο, εἶπέν τις τῶν μαθητῶν αὐτοῦ πρὸς αὐτόν, Κύριε, δίδαξον ἡμᾶς προσεύχεσθαι, καθὼς καὶ Ἰωάννης ἐδίδαξεν τοὺς μαθητὰς αὐτοῦ.', 'Kai egeneto en tō einai auton en topō tini proseuchomenon, hōs epausato, eipen tis tōn mathētōn autou pros auton, Kurie, didaxon hēmas proseuchesthai, kathōs kai Iōannēs edidaxen tous mathētas autou.', 'The unspecified "certain place" draws attention not to geography but to the practice itself: Jesus is found praying, as at his baptism (3:21), before calling the twelve (6:12), at Caesarea Philippi (9:18), and the transfiguration (9:28). The disciples'' request reveals that Jesus''s prayer life was visibly distinctive — something that inspired imitation rather than instruction. John the Baptist also taught his disciples a form of prayer, indicating that distinctive prayer marked the school of each teacher.', NULL),
  (2, 'And he said unto them, When ye pray, say, Our Father which art in heaven, Hallowed be thy name. Thy kingdom come. Thy will be done, as in heaven, so in earth.', 'εἶπεν δὲ αὐτοῖς, Ὅταν προσεύχησθε, λέγετε, Πάτερ, ἁγιασθήτω τὸ ὄνομά σου· ἐλθέτω ἡ βασιλεία σου·', 'eipen de autois, Hotan proseuchēsthe, legete, Pater, hagiasthētō to onoma sou; elthetō hē basileia sou;', 'Luke''s version is shorter than Matthew 6:9-13, omitting "which art in heaven," "thy will be done," "deliver us from evil," and the doxology. "Father" (Pater) alone — without qualification — reflects the Aramaic Abba, an intimacy unknown in pre-Christian Jewish public liturgy. "Hallowed be thy name" (hagiasthētō — aorist passive imperative) is not merely a wish but a petition: may you cause your name to be sanctified in the world. "Thy kingdom come" is the great eschatological longing driving all Christian prayer.', NULL),
  (3, 'Give us day by day our daily bread.', 'τὸν ἄρτον ἡμῶν τὸν ἐπιούσιον δίδου ἡμῖν τὸ καθ'' ἡμέραν·', 'ton arton hēmōn ton epiousion didou hēmin to kath'' hēmeran;', '"Daily bread" translates epiousios — a rare Greek word found almost exclusively in the Lord''s Prayer, possibly meaning "for the coming day," "sufficient for existence," or "supersubstantial." In Luke it is present tense (didou — keep giving, continuous action), emphasizing daily dependence in contrast to Matthew''s aorist. The rhythm of daily petition forms disciples into a posture of continual trust rather than autonomous self-sufficiency.', NULL),
  (4, 'And forgive us our sins; for we also forgive every one that is indebted to us. And lead us not into temptation; but deliver us from evil.', 'καὶ ἄφες ἡμῖν τὰς ἁμαρτίας ἡμῶν, καὶ γὰρ αὐτοὶ ἀφίομεν παντὶ ὀφείλοντι ἡμῖν· καὶ μὴ εἰσενέγκῃς ἡμᾶς εἰς πειρασμόν.', 'kai aphes hēmin tas hamartias hēmōn, kai gar autoi aphiomen panti opheilonti hēmin; kai mē eisenengkēs hēmas eis peirasmon.', 'Luke uses "sins" (hamartias) where Matthew uses "debts" (opheilēmata). The linking of divine forgiveness with our forgiving others is conditional-explanatory, not transactional: our readiness to forgive demonstrates that we understand forgiveness and genuinely need it. "Lead us not into temptation" (peirasmon — trial, testing) petitions that God would not bring us into situations that would overwhelm us; it does not imply God tempts (Jas 1:13) but asks for merciful guidance around the severest tests.', NULL),
  (5, 'And he said unto them, Which of you shall have a friend, and shall go unto him at midnight, and say unto him, Friend, lend me three loaves;', 'Καὶ εἶπεν πρὸς αὐτούς, Τίς ἐξ ὑμῶν ἕξει φίλον καὶ πορεύσεται πρὸς αὐτὸν μεσονυκτίου καὶ εἴπῃ αὐτῷ, Φίλε, χρῆσόν μοι τρεῖς ἄρτους,', 'Kai eipen pros autous, Tis ex humōn hexei philon kai poreusetai pros auton mesonuktiou kai eipē autō, Phile, chrēson moi treis artous,', 'The parable begins with a rhetorical question expecting the answer "no one would refuse." "At midnight" (mesonuktiou) is the most inconvenient hour, heightening the test. Three loaves was a normal meal for one traveler. The social setting of ancient Palestinian hospitality meant that failure to provide for a guest was a community shame, compelling the host to seek help even at great personal cost.', NULL),
  (6, 'For a friend of mine in his journey is come to me, and I have nothing to set before him?', 'ἐπειδὴ φίλος μου παρεγένετο ἐξ ὁδοῦ πρός με καὶ οὐκ ἔχω ὃ παραθήσω αὐτῷ·', 'epeidē philos mou paregeneto ex hodou pros me kai ouk echō ho parathēsō autō;', 'The urgency is compounded: not a personal want but a sacred obligation of hospitality. A traveling friend has arrived unexpectedly — a common reality when reliable lodging was scarce. The host''s "I have nothing" (ouk echō — absolute depletion) emphasizes that the request is made from genuine need, not convenience, establishing the right spirit for the petition.', NULL),
  (7, 'And he from within shall answer and say, Trouble me not: the door is now shut, and my children are with me in bed; I cannot rise and give thee.', 'κἀκεῖνος ἔσωθεν ἀποκριθεὶς εἴπῃ, Μή μοι κόπους πάρεχε· ἤδη ἡ θύρα κέκλεισται, καὶ τὰ παιδία μου μετ'' ἐμοῦ εἰς τὴν κοίτην εἰσίν· οὐ δύναμαι ἀναστὰς δοῦναί σοι.', 'kakEinos esōthen apokritheis eipē, Mē moi kopous pareche; ēdē hē thura kekleistai, kai ta paidia mou met'' emou eis tēn koitēn eisin; ou dunamai anastas dounai soi.', 'In a typical Palestinian peasant home — one room — the whole family slept together on a raised mat. Rising would disturb everyone. "The door is now shut" (kekleistai — perfect passive, firmly closed) suggests a heavy wooden bar. The refusal is practical, not malicious. The point of the parable is that even this reluctant neighbor will eventually help, making God''s willingness to answer all the more certain.', NULL),
  (8, 'I say unto you, Though he will not rise and give him, because he is his friend, yet because of his importunity he will rise and give him as many as he needeth.', 'λέγω ὑμῖν, εἰ καὶ οὐ δώσει αὐτῷ ἀναστὰς διὰ τὸ εἶναι φίλον αὐτοῦ, διά γε τὴν ἀναίδειαν αὐτοῦ ἐγερθεὶς δώσει αὐτῷ ὅσων χρῄζει.', 'legō humin, ei kai ou dōsei autō anastas dia to einai philon autou, dia ge tēn anaideian autou egertheis dōsei autō hosōn chrēzei.', 'The key word is anaideia — translated "importunity" but literally "shamelessness" or "bold persistence that refuses to be shamed away." The argument a fortiori: if a reluctant human neighbor ultimately gives because of shameless persistence, how much more will the Father — who is neither reluctant nor needing to be woken — give to those who ask. Prayer is not overcoming God''s reluctance but expressing our dependence.', NULL),
  (9, 'And I say unto you, Ask, and it shall be given you; seek, and ye shall find; knock, and it shall be opened unto you.', 'κἀγὼ ὑμῖν λέγω, αἰτεῖτε, καὶ δοθήσεται ὑμῖν· ζητεῖτε, καὶ εὑρήσετε· κρούετε, καὶ ἀνοιγήσεται ὑμῖν.', 'kagō humin legō, aiteite, kai dothēsetai humin; zēteite, kai heurēsete; krouete, kai anoigēsetai humin.', 'The three imperatives — ask (aiteite), seek (zēteite), knock (krouete) — are all present tense, indicating continuous action: keep asking, keep seeking, keep knocking. This is not a one-time formula but a lifestyle of prayer. The verbs escalate in intensity: asking is verbal petition, seeking is active movement, knocking is deliberate assertive appeal at a closed door. All three carry the unconditional promise of divine response.', NULL),
  (10, 'For every one that asketh receiveth; and he that seeketh findeth; and to him that knocketh it shall be opened.', 'πᾶς γὰρ ὁ αἰτῶν λαμβάνει, καὶ ὁ ζητῶν εὑρίσκει, καὶ τῷ κρούοντι ἀνοιγήσεται.', 'pas gar ho aitōn lambanei, kai ho zētōn heuriskei, kai tō krouonti anoigēsetai.', 'Verse 10 restates verse 9 as universal principle: "every one" (pas) who asks receives. The shift from command (v.9) to declaration (v.10) confirms the reliability of the promise. Present participles (the one asking, the one seeking, the one knocking) reinforce continuity of action. This is among the most absolute prayer promises in the NT; its qualification comes from context: asking the Father in alignment with his kingdom purposes.', NULL),
  (11, 'If a son shall ask bread of any of you that is a father, will he give him a stone? or if he ask a fish, will he for a fish give him a serpent?', 'τίνα δὲ ἐξ ὑμῶν τὸν πατέρα αἰτήσει ὁ υἱὸς ἄρτον, μὴ λίθον ἐπιδώσει αὐτῷ; ἢ καὶ ἰχθύν, μὴ ἀντὶ ἰχθύος ὄφιν αὐτῷ ἐπιδώσει;', 'tina de ex humōn ton patera aitēsei ho huios arton, mē lithon epidōsei autō; ē kai ichthun, mē anti ichthyos ophin autō epidōsei;', 'Jesus moves from human neighbor to human father — a closer, warmer relationship — to establish the certainty of God''s giving. No father would give a stone when asked for bread (superficially similar shapes) or a serpent when asked for a fish. The rhetorical questions (mē — expecting "surely not!") argue that even fallen human parents instinctively give good gifts to their children.', NULL),
  (12, 'Or if he shall ask an egg, will he offer him a scorpion?', 'ἢ καὶ αἰτήσει ᾠόν, μὴ ἐπιδώσει αὐτῷ σκορπίον;', 'ē kai aitēsei ōon, mē epidōsei autō skorpion;', 'An egg and a curled-up scorpion have some visual resemblance. This third pair completes the trio of parental absurdities and is unique to Luke''s version (Matthew 7:9-10 has only bread-stone and fish-serpent). Scorpions were a real danger in Palestine; the comparison was vivid and relatable. The escalating list of impossibles drives home that God cannot give harmful things to those who ask him.', NULL),
  (13, 'If ye then, being evil, know how to give good gifts unto your children: how much more shall your heavenly Father give the Holy Spirit to them that ask him?', 'εἰ οὖν ὑμεῖς πονηροὶ ὑπάρχοντες οἴδατε δόματα ἀγαθὰ διδόναι τοῖς τέκνοις ὑμῶν, πόσῳ μᾶλλον ὁ πατὴρ ὁ ἐξ οὐρανοῦ δώσει πνεῦμα ἅγιον τοῖς αἰτοῦσιν αὐτόν.', 'ei oun humeis ponēroi huparchontes oidate domata agatha didonai tois teknois humōn, posō mallon ho patēr ho ex ouranou dōsei pneuma hagion tois aitousin auton.', 'The climax: if you — described honestly as "evil" (ponēroi — fallen, morally compromised) — know how to give good gifts, how much more will the Father give the Holy Spirit. Significantly, where Matthew 7:11 reads "good things," Luke reads "the Holy Spirit" — the supreme gift and the essence of all good gifts. This shifts the entire prayer promise from material to spiritual: the ultimate answer to all prayer is God himself given to us.', NULL),
  (14, 'And he was casting out a devil, and it was dumb. And it came to pass, when the devil was gone out, the dumb spake; and the people wondered.', 'Καὶ ἦν ἐκβάλλων δαιμόνιον, καὶ αὐτὸ ἦν κωφόν· ἐγένετο δὲ τοῦ δαιμονίου ἐξελθόντος ἐλάλησεν ὁ κωφός, καὶ ἐθαύμασαν οἱ ὄχλοι.', 'Kai ēn ekballōn daimonion, kai auto ēn kōphon; egeneto de tou daimoniou exelthontos elalēsen ho kōphos, kai ethaumasan hoi ochloi.', 'The imperfect "was casting out" (ēn ekballōn) suggests an ongoing scene. "Dumb" (kōphon) means mute — the demonic affliction silenced the victim''s voice. The instant restoration of speech upon exorcism visibly demonstrates Jesus''s superior authority. The crowd''s wonder (ethaumasan) is the expected response, but wonder alone does not equal faith, as the following controversy immediately reveals.', NULL),
  (15, 'But some of them said, He casteth out devils through Beelzebub the chief of the devils.', 'τινὲς δὲ ἐξ αὐτῶν εἶπον, Ἐν Βεελζεβοὺλ τῷ ἄρχοντι τῶν δαιμονίων ἐκβάλλει τὰ δαιμόνια·', 'tines de ex autōn eipon, En Beelzeboul tō archonti tōn daimoniōn ekballei ta daimonia;', 'Beelzebub (Beelzeboul in Greek) derives from Baal-zebul ("lord of the exalted house") — a Philistine deity mocked in the OT as Baal-zebub ("lord of flies," 2 Kgs 1:2). By the NT period it had become a name for Satan or a chief demon. The accusation is the most blasphemous possible — attributing the work of the Spirit to the devil — representing willful blindness to the most obvious truth.', NULL),
  (16, 'And others, tempting him, sought of him a sign from heaven.', 'ἕτεροι δὲ πειράζοντες σημεῖον ἐξ οὐρανοῦ ἐζήτουν παρ'' αὐτοῦ.', 'heteroi de peirazOntes sēmeion ex ouranou ezētoun par'' autou.', 'A second group refuses to engage with the exorcism at all and demands a celestial sign — something astronomical and unmistakably divine. "Tempting" (peirazOntes — testing, putting to the proof) echoes the devil''s temptation in chapter 4. To demand a sign after witnessing exorcisms is not evidence-seeking but a posture of pre-determined unbelief; no evidence will satisfy those committed to rejection.', NULL),
  (17, 'But he, knowing their thoughts, said unto them, Every kingdom divided against itself is brought to desolation; and a house divided against a house falleth.', 'αὐτὸς δὲ εἰδὼς αὐτῶν τὰ διανοήματα εἶπεν αὐτοῖς, Πᾶσα βασιλεία ἐφ'' ἑαυτὴν διαμερισθεῖσα ἐρημοῦται, καὶ οἶκος ἐπὶ οἶκον πίπτει.', 'autos de eidōs autōn ta dianoēmata eipen autois, Pasa basileia eph'' heautēn diameristheisa erēmoutai, kai oikos epi oikon piptei.', '"Knowing their thoughts" (eidōs ta dianoēmata) — supernatural perception (cf. 5:22; 6:8; 7:39-40), which is itself evidence of divine knowledge. The political analogy is immediately compelling: no kingdom destroys itself by fighting itself; division produces desolation (erēmoutai — made into a wasteland). The principle applies at every level from households to empires to the spiritual realm.', NULL),
  (18, 'If Satan also be divided against himself, how shall his kingdom stand? because ye say that I cast out devils through Beelzebub.', 'εἰ δὲ καὶ ὁ Σατανᾶς ἐφ'' ἑαυτὸν διεμερίσθη, πῶς σταθήσεται ἡ βασιλεία αὐτοῦ; ὅτι λέγετε ἐν Βεελζεβοὺλ ἐκβάλλειν με τὰ δαιμόνια.', 'ei de kai ho Satanas eph'' heauton diemeristhē, pōs stathēsetai hē basileia autou; hoti legete en Beelzeboul ekballein me ta daimonia.', 'The reductio ad absurdum: if I cast out Satan''s demons by Satan''s power, then Satan is fighting himself and his kingdom cannot stand. Yet the accusers observe that the kingdom of darkness remains active and coherent. Therefore the premise is false: the exorcisms cannot be Satanic. The argument is logically decisive, exposing the accusation as self-contradictory.', NULL),
  (19, 'And if I by Beelzebub cast out devils, by whom do your sons cast them out? therefore shall they be your judges.', 'εἰ δὲ ἐγὼ ἐν Βεελζεβοὺλ ἐκβάλλω τὰ δαιμόνια, οἱ υἱοὶ ὑμῶν ἐν τίνι ἐκβάλλουσιν; διὰ τοῦτο αὐτοὶ ὑμῶν κριταὶ ἔσονται.', 'ei de egō en Beelzeboul ekballō ta daimonia, hoi huioi humōn en tini ekballousin; dia touto autoi humōn kritai esontai.', 'Jewish exorcists existed (cf. Acts 19:13-14) and were regarded by the Pharisees as legitimate. If Jesus''s exorcisms are demonic, by what principle do the Pharisees'' own disciples operate? To accuse Jesus is to implicitly condemn their own students. "Your sons" — their disciples or fellow Jews who practiced exorcism — become unwitting judges against the Pharisees'' double standard.', NULL),
  (20, 'But if I with the finger of God cast out devils, no doubt the kingdom of God is come upon you.', 'εἰ δὲ ἐν δακτύλῳ Θεοῦ ἐκβάλλω τὰ δαιμόνια, ἄρα ἔφθασεν ἐφ'' ὑμᾶς ἡ βασιλεία τοῦ Θεοῦ.', 'ei de en daktulō Theou ekballō ta daimonia, ara ephthasen eph'' humas hē basileia tou Theou.', '"The finger of God" (daktulō Theou) is the Exodus motif: the Egyptian magicians attributed the plague of gnats to "the finger of God" (Exod 8:19), recognizing power beyond human manipulation. Matthew 12:28 reads "Spirit of God" — "finger of God" is Luke''s formulation, intensifying the OT typology. "Is come upon you" (ephthasen — has arrived, already come) declares the kingdom present, not merely near.', NULL),
  (21, 'When a strong man armed keepeth his palace, his goods are in peace:', 'ὅταν ὁ ἰσχυρὸς καθωπλισμένος φυλάσσῃ τὴν ἑαυτοῦ αὐλήν, ἐν εἰρήνῃ ἐστὶν τὰ ὑπάρχοντα αὐτοῦ·', 'hotan ho ischuros kathōplismenos phulassē tēn heautou aulēn, en eirēnē estin ta huparchonta autou;', 'The "strong man" (ischuros) represents Satan, who holds souls as his possessions. "Armed" (kathōplismenos — fully equipped, panoplied) indicates watchful, deliberate power. "His palace" (tēn aulēn — courtyard, homestead) is the world under his dominion. "In peace" ironically describes those enslaved to him — undisturbed, because no one stronger has yet appeared. The parable frames exorcism as a declaration of cosmic war.', NULL),
  (22, 'But when a stronger than he shall come upon him, and overcome him, he taketh from him all his armour wherein he trusted, and divideth his spoils.', 'ἐπὰν δὲ ἰσχυρότερος αὐτοῦ ἐπελθὼν νικήσῃ αὐτόν, τὴν πανοπλίαν αὐτοῦ αἴρει ἐφ'' ᾗ ἐπεποίθει, καὶ τὰ σκῦλα αὐτοῦ διαδίδωσιν.', 'epan de ischuroteros autou epelthōn nikēsē auton, tēn panoplian autou airei eph'' hē epepoithei, kai ta skula autou diadidōsin.', 'The "stronger one" (ischuroteros) is Jesus — announced by John (3:16: "one mightier than I"). The full armor (panoplian — the entire military equipment) is taken, stripping Satan of the authority he trusted. "Divideth his spoils" — the liberated captives are distributed as gifts: souls freed from bondage. The cross is the ultimate enactment of this parable (Col 2:15; John 12:31), of which every exorcism is an anticipation.', NULL),
  (23, 'He that is not with me is against me: and he that gathereth not with me scattereth.', 'ὁ μὴ ὢν μετ'' ἐμοῦ κατ'' ἐμοῦ ἐστιν, καὶ ὁ μὴ συνάγων μετ'' ἐμοῦ σκορπίζει.', 'ho mē ōn met'' emou kat'' emou estin, kai ho mē sunagōn met'' emou skorpizei.', 'In this eschatological moment — when the kingdom is arriving and the strong man is being bound — neutrality is impossible. "Gathereth" (sunagōn — assembling, harvesting) and "scattereth" (skorpizei — disperses the flock) are shepherd images. The statement directly addresses those who attempted to explain away Jesus''s exorcisms without joining his mission. There is no middle ground: one either joins or opposes.', NULL),
  (24, 'When the unclean spirit is gone out of a man, he walketh through dry places, seeking rest; and finding none, he saith, I will return unto my house whence I came out.', 'Ὅταν τὸ ἀκάθαρτον πνεῦμα ἐξέλθῃ ἀπὸ τοῦ ἀνθρώπου, διέρχεται δι'' ἀνύδρων τόπων ζητοῦν ἀνάπαυσιν, καὶ μὴ εὑρίσκον λέγει, Ὑποστρέψω εἰς τὸν οἶκόν μου ὅθεν ἐξῆλθον.', 'Hotan to akatharton pneuma exelthē apo tou anthrōpou, dierchetai di'' anudrōn topōn zētoun anapausin, kai mē heuriskon legei, Hupostrepsō eis ton oikon mou hothen exēlthon.', '"Dry places" (anhudrōn topōn) — waterless, desert regions associated with demonic habitation (Isa 13:21; 34:14). Demons are portrayed as seeking a resting place (anapausin — rest, cessation) within a human host. The spirit calls the former host "my house" — indicating the possessive claim demons make on those they inhabit. The primary application is to Israel after John''s cleansing ministry: swept but not filled with the Spirit.', NULL),
  (25, 'And when he cometh, he findeth it swept and garnished.', 'καὶ ἐλθὸν εὑρίσκει σεσαρωμένον καὶ κεκοσμημένον.', 'kai elthon heuriskei sesarōmenon kai kekosmēmenon.', '"Swept" (sesarōmenon — brushed clean, having been swept) and "garnished" (kekosmēmenon — adorned, arranged, in order) describes a house cleaned but left empty. External reformation without spiritual infilling creates a dangerous vacuum. The house is presentable — the outward life may appear reformed — but it is unoccupied by the Holy Spirit, making it vulnerable to reoccupation by worse forces.', NULL),
  (26, 'Then goeth he, and taketh to him seven other spirits more wicked than himself; and they enter in, and dwell there: and the last state of that man is worse than the first.', 'τότε πορεύεται καὶ παραλαμβάνει ἕτερα πνεύματα πονηρότερα ἑαυτοῦ ἑπτά, καὶ εἰσελθόντα κατοικεῖ ἐκεῖ· καὶ γίνεται τὰ ἔσχατα τοῦ ἀνθρώπου ἐκείνου χείρονα τῶν πρώτων.', 'tote poreuetai kai paralambanei hetera pneumata ponērotera heautou hepta, kai eiselthonta katoikei ekei; kai ginetai ta eschata tou anthrōpou ekeinou cheirona tōn prōtōn.', '"Seven" (hepta) is the number of completeness — a complete force of wickedness. "Dwell there" (katoikei — to settle permanently; stronger than paroikei, to sojourn) indicates settled occupation. "The last state worse than the first" (ta eschata cheirona tōn prōtōn) warns that incomplete deliverance not followed by true conversion and Spirit-filling results in worse bondage — applied directly to the generation hearing Jesus.', NULL),
  (27, 'And it came to pass, as he spake these things, a certain woman of the company lifted up her voice, and said unto him, Blessed is the womb that bare thee, and the paps which thou hast sucked.', 'Ἐγένετο δὲ ἐν τῷ λέγειν αὐτὸν ταῦτα ἐπάρασά τις φωνὴν γυνὴ ἐκ τοῦ ὄχλου εἶπεν αὐτῷ, Μακαρία ἡ κοιλία ἡ βαστάσασά σε καὶ μαστοὶ οὓς ἐθήλασας.', 'Egeneto de en tō legein auton tauta eparasa tis phōnēn gunē ek tou ochlou eipen autō, Makaria hē koilia hē bastasasa se kai mastoi hous ethelasas.', 'A woman spontaneously cries out a macarism (beatitude) — a natural Jewish expression of blessing for the mother of an honored son (cf. 1:42, Elizabeth''s similar blessing). "Blessed is the womb" celebrates Mary''s unique motherhood. Luke includes this precisely to lead into Jesus''s corrective and deeper beatitude, redirecting blessing from biological kinship to spiritual receptivity.', NULL),
  (28, 'But he said, Yea rather, blessed are they that hear the word of God, and keep it.', 'αὐτὸς δὲ εἶπεν, Μενοῦν μακάριοι οἱ ἀκούοντες τὸν λόγον τοῦ Θεοῦ καὶ φυλάσσοντες αὐτόν.', 'autos de eipen, Menoun makarioi hoi akouontes ton logon tou Theou kai phulassontes auton.', '"Yea rather" (menoun — on the contrary, indeed) does not negate the blessing on Mary but redirects to a greater beatitude available to all. Physical kinship with Jesus, however privileged, is not the foundation of blessing. The blessing that truly matters is hearing (akouontes — continually hearing) and keeping (phulassontes — guarding, observing) the word of God. This echoes 8:21 and invites every hearer into the same privileged relationship Mary enjoyed.', NULL),
  (29, 'And when the people were gathered thick together, he began to say, This is an evil generation: they seek a sign; and there shall no sign be given it, but the sign of Jonas the prophet.', 'Τῶν δὲ ὄχλων ἐπαθροιζομένων ἤρξατο λέγειν, Ἡ γενεὰ αὕτη γενεὰ πονηρά ἐστιν· σημεῖον ζητεῖ, καὶ σημεῖον οὐ δοθήσεται αὐτῇ εἰ μὴ τὸ σημεῖον Ἰωνᾶ.', 'Tōn de ochlōn epathroizomenōn ērxato legein, Hē genea hautē genea ponēra estin; sēmeion zētei, kai sēmeion ou dothēsetai autē ei mē to sēmeion Iōna.', 'As the crowd swells, Jesus addresses the corporate spiritual condition of "this generation" — a term of moral evaluation. Demanding a sign after witnessing exorcisms reveals a heart that will not be satisfied by any evidence and uses sign-seeking as an escape from moral accountability. The only sign granted is "the sign of Jonas" — cryptic, requiring interpretation, pointing to resurrection and judgment.', NULL),
  (30, 'For as Jonas was a sign unto the Ninevites, so shall also the Son of man be to this generation.', 'καθὼς γὰρ ἐγένετο Ἰωνᾶς τοῖς Νινευίταις σημεῖον, οὕτως ἔσται καὶ ὁ Υἱὸς τοῦ ἀνθρώπου τῇ γενεᾷ ταύτῃ.', 'kathōs gar egeneto Iōnas tois Nineuitas sēmeion, houtōs estai kai ho Huios tou anthrōpou tē genea tautē.', 'Jonah was himself the sign — his person and proclamation — not merely the miracle of the great fish. Matthew 12:40 identifies the sign as three days in the fish''s belly (pointing to resurrection). Luke emphasizes the prophetic proclamation: as Jonah''s preaching called Nineveh to repentance, so the Son of Man — his death and resurrection — will be the decisive sign of eschatological judgment and salvation.', NULL),
  (31, 'The queen of the south shall rise up in the judgment with the men of this generation, and condemn them: for she came from the utmost parts of the earth to hear the wisdom of Solomon; and, behold, a greater than Solomon is here.', 'βασίλισσα νότου ἐγερθήσεται ἐν τῇ κρίσει μετὰ τῶν ἀνδρῶν τῆς γενεᾶς ταύτης καὶ κατακρινεῖ αὐτούς· ὅτι ἦλθεν ἐκ τῶν περάτων τῆς γῆς ἀκοῦσαι τὴν σοφίαν Σολομῶντος, καὶ ἰδοὺ πλεῖον Σολομῶντος ὧδε.', 'basilissa notou egerthēsetai en tē krisei meta tōn andrōn tēs geneas tautēs kai katakrinei autous; hoti ēlthen ek tōn peratōn tēs gēs akousai tēn sophian Solomōntos, kai idou pleion Solomōntos hōde.', 'The queen of Sheba (1 Kgs 10:1-13) traveled vast distances to hear wisdom. At the judgment she will stand as a witness against those who had Wisdom himself in their midst and refused to listen. "A greater than Solomon is here" (pleion Solomōntos — more than Solomon, a neuter comparative suggesting quality beyond category) — not merely a wiser teacher but the Wisdom of God incarnate.', NULL),
  (32, 'The men of Nineveh shall rise up in the judgment with this generation, and shall condemn it: for they repented at the preaching of Jonas; and, behold, a greater than Jonas is here.', 'ἄνδρες Νινευῖται ἀναστήσονται ἐν τῇ κρίσει μετὰ τῆς γενεᾶς ταύτης καὶ κατακρινοῦσιν αὐτήν· ὅτι μετενόησαν εἰς τὸ κήρυγμα Ἰωνᾶ, καὶ ἰδοὺ πλεῖον Ἰωνᾶ ὧδε.', 'andres Nineuītai anastēsontai en tē krisei meta tēs geneas tautēs kai katakrinousin autēn; hoti metenoēsan eis to kērugma Iōna, kai idou pleion Iōna hōde.', 'The Ninevites repented (metenoēsan — changed mind and direction completely) at the preaching of a reluctant, ungracious prophet who gave them no miracles, only a brief word of judgment. Yet Israel, hearing the Son of God preach with signs and wonders, refuses to repent. The Ninevites'' response condemns this generation because they did more with less. "Greater than Jonah" closes the double indictment.', NULL),
  (33, 'No man, when he hath lighted a candle, putteth it in a secret place, neither under a bushel, but on a candlestick, that they which come in may see the light.', 'Οὐδεὶς λύχνον ἅψας εἰς κρύπτην τίθησιν οὐδὲ ὑπὸ τὸν μόδιον, ἀλλ'' ἐπὶ τὴν λυχνίαν, ἵνα οἱ εἰσπορευόμενοι τὸ φέγγος βλέπωσιν.', 'Oudeis luchnon hapsas eis kruptēn tithēsin oude hupo ton modion, all'' epi tēn luchnian, hina hoi eisporeuomenoi to phengos blepōsin.', 'This lamp saying (cf. 8:16) applied in this context refers primarily to Jesus himself — he is the lamp placed on the stand for all who enter. His coming is not hidden but fully public. The "secret place" (kruptēn — crypt, hidden recess) and "bushel" (modion — a measuring basket) represent the obscuring of divine revelation, which Jesus refuses to do, placing his light where all may see.', NULL),
  (34, 'The light of the body is the eye: therefore when thine eye is single, thy whole body also is full of light; but when thine eye is evil, thy body also is full of darkness.', 'ὁ λύχνος τοῦ σώματός ἐστιν ὁ ὀφθαλμός σου· ὅταν ὁ ὀφθαλμός σου ἁπλοῦς ᾖ, καὶ ὅλον τὸ σῶμά σου φωτεινόν ἐστιν· ἐπὰν δὲ πονηρὸς ᾖ, καὶ τὸ σῶμά σου σκοτεινόν ἐστιν.', 'ho luchnos tou sōmatos estin ho ophthalmos sou; hotan ho ophthalmos sou haploūs ē, kai holon to sōma sou phōteinon estin; epan de ponēros ē, kai to sōma sou skoteinon estin.', '"Single" (haploūs — clear, sound, simple, generous) means an eye fully open to light, not squinting or clouded. In Jewish idiom an "evil eye" (ponēros) meant stinginess or envy (Prov 28:22), while a "single/good eye" meant generosity. Applied here: receptivity to Jesus''s revelation — an open, willing, undivided heart — fills the whole person with divine light, while resistance to his word produces comprehensive moral darkness.', NULL),
  (35, 'Take heed therefore that the light which is in thee be not darkness.', 'σκόπει οὖν μὴ τὸ φῶς τὸ ἐν σοὶ σκότος ἐστίν.', 'skopei oun mē to phōs to en soi skotos estin.', 'A solemn warning: it is possible to believe one possesses light while actually being in darkness. The Pharisees were convinced they had the light of Torah and tradition while Jesus declares them darkened. "Take heed" (skopei — watch carefully, examine) calls for honest self-examination. The most dangerous form of darkness is the darkness that calls itself light — a condition Jesus will expose in the following woes.', NULL),
  (36, 'If thy whole body therefore be full of light, having no part dark, the whole shall be full of light, as when the bright shining of a candle doth give thee light.', 'εἰ οὖν τὸ σῶμά σου ὅλον φωτεινόν, μὴ ἔχον τι μέρος σκοτεινόν, ἔσται φωτεινὸν ὅλον ὡς ὅταν ὁ λύχνος τῇ ἀστραπῇ φωτίζῃ σε.', 'ei oun to sōma sou holon phōteinon, mē echon ti meros skoteinon, estai phōteinon holon hōs hotan ho luchnos tē astrapē phōtizē se.', 'The positive vision: a body entirely filled with light — no dark compartment, no hidden area of resistance — radiates like a lamp that illuminates with a brilliance (astrapē — lightning flash, radiance). The word astrapē (used for lightning in 17:24) suggests dazzling completeness. This is the condition of the fully receptive disciple — illumined entirely by Christ, with no sector of life held back from his lordship.', NULL),
  (37, 'And as he spake, a certain Pharisee besought him to dine with him: and he went in, and sat down to meat.', 'Ἐν δὲ τῷ λαλῆσαι ἐρωτᾷ αὐτὸν Φαρισαῖός τις ὅπως ἀριστήσῃ παρ'' αὐτῷ· εἰσελθὼν δὲ ἀνέπεσεν.', 'En de tō lalēsai erōtā auton Pharisaios tis hopōs aristēsē par'' autō; eiselthōn de anepesen.', 'For the second time in Luke (cf. 7:36), Jesus dines with a Pharisee. Jesus accepts hospitality across social boundaries — he is not sectarian — but every meal in Luke becomes a place of confrontation and teaching. "Sat down to meat" (anepesen — reclined) indicates the full formal dinner posture. What follows is not a personal attack but an exposure of systemic corruption in the religion of Israel.', NULL),
  (38, 'And when the Pharisee saw it, he marvelled that he had not first washed before dinner.', 'ὁ δὲ Φαρισαῖος ἰδὼν ἐθαύμασεν ὅτι οὐ πρῶτον ἐβαπτίσθη πρὸ τοῦ ἀρίστου.', 'ho de Pharisaios idōn ethaumasen hoti ou prōton ebaptisthē pro tou aristou.', '"Washed" (ebaptisthē — baptized, immersed) refers to the Pharisaic practice of ritual handwashing before meals (Lev 15; Mark 7:1-5). Jesus''s omission was deliberate — a statement about the priority of inner purity over ritual washing. The Pharisee''s shock (ethaumasen — marveled) reveals how central these external performances were to Pharisaic identity and how threatening their omission appeared.', NULL),
  (39, 'And the Lord said unto him, Now do ye Pharisees make clean the outside of the cup and the platter; but your inward part is full of ravening and wickedness.', 'εἶπεν δὲ ὁ Κύριος πρὸς αὐτόν, Νῦν ὑμεῖς οἱ Φαρισαῖοι τὸ ἔξωθεν τοῦ ποτηρίου καὶ τοῦ πίνακος καθαρίζετε, τὸ δὲ ἔσωθεν ὑμῶν γέμει ἁρπαγῆς καὶ πονηρίας.', 'eipen de ho Kurios pros auton, Nun humeis hoi Pharisaioi to exōthen tou potēriou kai tou pinakos katharizete, to de esōthen humōn gemei harpagēs kai ponērias.', 'Luke uses "the Lord" (Kurios) as a narrative title underscoring divine authority. The cup and plate imagery is vivid: they scrupulously clean the outer surface of vessels while the inside is full of robbery (harpagēs — extortion, violent seizure) and wickedness (ponērias). The metaphor indicts the entire Pharisaic religious system: externally meticulous, internally corrupt.', NULL),
  (40, 'Ye fools, did not he that made that which is without make that which is within also?', 'ἄφρονες, οὐχ ὁ ποιήσας τὸ ἔξωθεν καὶ τὸ ἔσωθεν ἐποίησεν;', 'aphrones, ouch ho poiēsas to exōthen kai to esōthen epoiēsen?', '"Fools" (aphrones — mindless, without understanding) is a philosophical indictment: they lack the coherence to connect outward religion with inward reality. The rhetorical question is devastating: the God who created the outside of the cup also created the inside. He is concerned with both — indeed, with the inside first. To clean only the outside is to act as though God only sees surfaces, which is a profound theological error.', NULL),
  (41, 'But rather give alms of such things as ye have; and, behold, all things are clean unto you.', 'πλὴν τὰ ἐνόντα δότε ἐλεημοσύνην, καὶ ἰδοὺ πάντα καθαρὰ ὑμῖν ἐστιν.', 'plēn ta enonta dote eleēmosunēn, kai idou panta kathara humin estin.', 'The solution to Pharisaic hypocrisy is not more ritual washing but charitable giving from the heart — almsgiving (eleēmosunēn) flowing from genuine compassion rather than legal obligation. "Give alms of such things as ye have" addresses the interior problem of avarice (v.39). When the inside is clean — covetousness replaced by generosity — the whole person and their acts are truly clean.', NULL),
  (42, 'But woe unto you, Pharisees! for ye tithe mint and rue and all manner of herbs, and pass over judgment and the love of God: these ought ye to have done, and not to leave the other undone.', 'ἀλλὰ οὐαὶ ὑμῖν τοῖς Φαρισαίοις, ὅτι ἀποδεκατοῦτε τὸ ἡδύοσμον καὶ τὸ πήγανον καὶ πᾶν λάχανον, καὶ παρέρχεσθε τὴν κρίσιν καὶ τὴν ἀγάπην τοῦ Θεοῦ· ταῦτα δὲ ἔδει ποιῆσαι κἀκεῖνα μὴ παρεῖναι.', 'alla ouai humin tois Pharisaiois, hoti apodekatousthe to hēduosmon kai to pēganon kai pan lachanon, kai parerchesthe tēn krisin kai tēn agapēn tou Theou; tauta de edei poiēsai kakeina mē pareinai.', 'First woe against Pharisees. They tithed garden herbs — an extension of the Torah tithe (Deut 14:22-23) beyond grain, wine, and oil to the smallest plants — while "passing over" (parerchesthe — bypassing, neglecting) justice (krisin — righteous judgment, equity) and love of God. Jesus does not abolish tithing — "these ought ye to have done" — but declares that meticulous externals divorced from core moral obligations is perversion, not piety.', NULL),
  (43, 'Woe unto you, Pharisees! for ye love the uppermost seats in the synagogues, and greetings in the markets.', 'οὐαὶ ὑμῖν τοῖς Φαρισαίοις, ὅτι ἀγαπᾶτε τὴν πρωτοκαθεδρίαν ἐν ταῖς συναγωγαῖς καὶ τοὺς ἀσπασμοὺς ἐν ταῖς ἀγοραῖς.', 'ouai humin tois Pharisaiois, hoti agapate tēn prōtokathedrian en tais sunagōgais kai tous aspasmous en tais agorais.', 'Second woe against Pharisees. "The uppermost seats" (prōtokathedrian — the prominent seat facing the congregation in the synagogue) and public greetings (aspasmous — elaborate salutations acknowledging status) reveal a religion driven by the love of honor. "Ye love" (agapate) — the noblest word for love, here applied to vanity. True piety is content to be unknown; Pharisaic religion requires an audience.', NULL),
  (44, 'Woe unto you, scribes and Pharisees, hypocrites! for ye are as graves which appear not, and the men that walk over them are not aware of them.', 'οὐαὶ ὑμῖν, ὅτι ἐστὲ ὡς τὰ μνημεῖα τὰ ἄδηλα, καὶ οἱ ἄνθρωποι οἱ περιπατοῦντες ἐπάνω οὐκ οἴδασιν.', 'ouai humin, hoti este hōs ta mnēmeia ta adēla, kai hoi anthrōpoi hoi peripatountes epanō ouk oidasin.', 'Third woe against Pharisees. In Matthew 23:27 the comparison is to whitewashed tombs — visible and beautiful outside. Here in Luke the emphasis is invisible unmarked graves (adēla — not apparent, obscure), which defile those who walk over them unknowingly (Num 19:16). The Pharisees contaminate those who associate with them without either party realizing the spiritual defilement occurring — corruption spreading invisibly.', NULL),
  (45, 'Then answered one of the lawyers, and said unto him, Master, thus saying thou reproachest us also.', 'Ἀποκριθεὶς δέ τις τῶν νομικῶν λέγει αὐτῷ, Διδάσκαλε, ταῦτα λέγων καὶ ἡμᾶς ὑβρίζεις.', 'Apokritheis de tis tōn nomikōn legei autō, Didaskale, tauta legōn kai hēmas hubrizeis.', 'A lawyer (nomikos — expert in Torah, distinct from but overlapping with Pharisees) protests that the woes apply to his group as well. His tone is that of a man offended (hubrizeis — you insult, dishonor) rather than convicted. He identifies with the Pharisees in their shame rather than separating himself in repentance — and thereby unwittingly invites Jesus to deliver three additional woes directly against lawyers.', NULL),
  (46, 'And he said, Woe unto you also, ye lawyers! for ye lade men with burdens grievous to be borne, and ye yourselves touch not the burdens with one of your fingers.', 'ὁ δὲ εἶπεν, Καὶ ὑμῖν τοῖς νομικοῖς οὐαί, ὅτι φορτίζετε τοὺς ἀνθρώπους φορτία δυσβάστακτα, καὶ αὐτοὶ ἑνὶ τῶν δακτύλων ὑμῶν οὐ προσψαύετε τοῖς φορτίοις.', 'ho de eipen, Kai humin tois nomikois ouai, hoti phortizete tous anthrōpous phortia dusbastakta, kai autoi heni tōn daktulōn humōn ou prospsauete tois phortiois.', 'First woe against lawyers. They construct elaborate legal obligations — fence laws and interpretations — that crush ordinary people with impossible religious burdens (phortia dusbastakta — unbearable loads; cf. Matt 23:4). Yet they themselves do not touch these burdens with even one finger: they find exemptions and interpretive strategies that release the learned from what they impose on the ignorant — the ultimate betrayal of teaching authority.', NULL),
  (47, 'Woe unto you! for ye build the sepulchres of the prophets, and your fathers killed them.', 'οὐαὶ ὑμῖν, ὅτι οἰκοδομεῖτε τὰ μνημεῖα τῶν προφητῶν, οἱ δὲ πατέρες ὑμῶν ἀπέκτειναν αὐτούς.', 'ouai humin, hoti oikodomEite ta mnēmeia tōn prophētōn, hoi de pateres humōn apekteinan autous.', 'Second woe against lawyers. They build tombs for prophets whom their fathers murdered — an act of hypocritical commemoration. They honor the prophets in death while preparing to repeat their fathers'' sin against the living Prophet in their midst. Tomb-building, far from demonstrating honor, becomes evidence that they know which side of history their family stands on and have done nothing to depart from it.', NULL),
  (48, 'Truly ye bear witness that ye allow the deeds of your fathers: for they indeed killed them, and ye build their sepulchres.', 'ἄρα μάρτυρές ἐστε καὶ συνευδοκεῖτε τοῖς ἔργοις τῶν πατέρων ὑμῶν, ὅτι αὐτοὶ μὲν ἀπέκτειναν αὐτούς, ὑμεῖς δὲ οἰκοδομεῖτε.', 'ara martyres este kai sunEudokeite tois ergois tōn paterōn humōn, hoti autoi men apekteinan autous, humeis de oikodomEite.', '"Ye bear witness" (martyres este) — an ironic legal formulation: they are witnesses against themselves. "Allow" (sunEudokeite — you approve together with, consent to) is the same word Paul uses of those who applaud sin (Rom 1:32). By not condemning their fathers'' actions but commemorating the prophets as martyred heroes while preparing the same treatment for Jesus, they complete the circuit of prophet-killing.', NULL),
  (49, 'Therefore also said the wisdom of God, I will send them prophets and apostles, and some of them they shall slay and persecute:', 'διὰ τοῦτο καὶ ἡ σοφία τοῦ Θεοῦ εἶπεν, Ἀποστελῶ εἰς αὐτοὺς προφήτας καὶ ἀποστόλους, καὶ ἐξ αὐτῶν ἀποκτενοῦσιν καὶ ἐκδιώξουσιν,', 'dia touto kai hē sophia tou Theou eipen, Apostelō eis autous prophētas kai apostolous, kai ex autōn apoktenousin kai ekdiōxousin,', '"The wisdom of God" may be a citation formula for a lost wisdom tradition, or Jesus may be speaking as the personified Wisdom of God (Prov 8; cf. Matt 23:34 where Jesus says "I send"). Luke''s formulation is more elevated. The sending of prophets and apostles — including NT missionaries — is the continued pattern of divine outreach that this generation would continue to resist, as Acts would demonstrate.', NULL),
  (50, 'That the blood of all the prophets, which was shed from the foundation of the world, may be required of this generation;', 'ἵνα ἐκζητηθῇ τὸ αἷμα πάντων τῶν προφητῶν τὸ ἐκκεχυμένον ἀπὸ καταβολῆς κόσμου ἀπὸ τῆς γενεᾶς ταύτης,', 'hina ekzētēthē to haima pantōn tōn prophētōn to ekkechumEnon apo katabolēs kosmou apo tēs geneas tautēs,', '"Required" (ekzētēthē — sought out, called to account for). The generation that rejects Jesus — the culmination of the prophetic line — bears the accumulated guilt of all prophetic blood shed throughout redemptive history. This is not arbitrary collective punishment but the logic of corporate solidarity: they stand in the lineage of the murderers and are completing the work begun at the creation''s dawn.', NULL),
  (51, 'From the blood of Abel unto the blood of Zacharias, which perished between the altar and the temple: verily I say unto you, It shall be required of this generation.', 'ἀπὸ αἵματος Ἅβελ ἕως αἵματος Ζαχαρίου τοῦ ἀπολομένου μεταξὺ τοῦ θυσιαστηρίου καὶ τοῦ οἴκου· ναί, λέγω ὑμῖν, ἐκζητηθήσεται ἀπὸ τῆς γενεᾶς ταύτης.', 'apo haimatos Habel heōs haimatos Zachariou tou apolomenou metaxu tou thusiastēriou kai tou oikou; nai, legō humin, ekzētēthēsetai apo tēs geneas tautēs.', 'Abel (Gen 4:8) is the first murder victim in the OT narrative; Zechariah son of Jehoiada (2 Chr 24:20-22) is the last in Hebrew canonical order, killed in the temple court "between the altar and the temple" — dying in the center of Israel''s worship. This spans the entire OT martyrology. Jesus solemnly repeats the sentence, sealing the indictment with "Verily I say unto you."', NULL),
  (52, 'Woe unto you, lawyers! for ye have taken away the key of knowledge: ye entered not in yourselves, and them that were entering in ye hindered.', 'οὐαὶ ὑμῖν τοῖς νομικοῖς, ὅτι ἤρατε τὴν κλεῖδα τῆς γνώσεως· αὐτοὶ οὐκ εἰσήλθατε, καὶ τοὺς εἰσερχομένους ἐκωλύσατε.', 'ouai humin tois nomikois, hoti ērate tēn kleida tēs gnōseōs; autoi ouk eisēlthate, kai tous eiserchomenous ekōlusate.', 'Third and climactic woe against lawyers. "The key of knowledge" (tēn kleida tēs gnōseōs) — salvific understanding of the Scriptures that leads to the Messiah. By their interpretive traditions they have removed (ērate — taken away, confiscated) the very key that opens the door of salvation. They refused to enter and actively hindered those trying to enter — the ultimate professional betrayal of teachers who block the door of knowledge.', NULL),
  (53, 'And as he said these things unto them, the scribes and the Pharisees began to urge him vehemently, and to provoke him to speak of many things:', 'Κἀκεῖθεν ἐξελθόντος αὐτοῦ ἤρξαντο οἱ γραμματεῖς καὶ οἱ Φαρισαῖοι δεινῶς ἐνέχειν καὶ ἀποστοματίζειν αὐτὸν περὶ πλειόνων,', 'Kakeithen exelthontos autou ērxanto hoi grammateis kai hoi Pharisaioi deinōs enechein kai apostomatizein auton peri pleionōn,', '"Urge vehemently" (deinōs enechein — fiercely to hold against, to bear a bitter grudge) and "provoke to speak" (apostomatizein — to interrogate in order to trap, to elicit oral responses) reveal the transition from shocked silence to organized hostility. The seven woes have produced not repentance but rage, and a campaign of sharp questioning designed to extract something indictable.', NULL),
  (54, 'Laying wait for him, and seeking to catch something out of his mouth, that they might accuse him.', 'ἐνεδρεύοντες αὐτόν, ζητοῦντες θηρεῦσαί τι ἐκ τοῦ στόματος αὐτοῦ, ἵνα κατηγορήσωσιν αὐτοῦ.', 'enedreUontes auton, zētountes thēreusai ti ek tou stomatos autou, hina katēgorēsōsin autou.', '"Laying wait" (enedreUontes — setting an ambush, military terminology for a trap) and "to catch" (thēreusai — to hunt, to trap as a wild animal) portray the religious leaders as predators. They seek any quotable utterance that could be used as a legal accusation (katēgorēsōsin — to bring formal charges). This verse bridges to chapter 12, where Jesus warns his disciples of Pharisaic hypocrisy under the pressure of this mounting danger.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 11;

-- ═══════════════════════════════════════════════════
-- LUKE CHAPTER 11 — BACKFILL: Word Studies + Cross References
-- ═══════════════════════════════════════════════════

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'δίδαξον ἡμᾶς προσεύχεσθαι', 'didaxon hēmas proseuchesthai', 'G1321/G4336', 'Teach us to pray — the disciples watched Jesus''s prayer-life and wanted what he had. Prayer is modelled, then taught — caught before it is taught.', 1),
  (2, 'Πάτερ, ἁγιασθήτω', 'Pater, hagiasthētō', 'G3962/G37', 'Father, hallowed — Jesus grants his disciples the same intimate address (Pater / Abba) he himself uses with God. Hagiasthētō (aorist passive imperative) = let it be sanctified, set apart as holy.', 2),
  (2, 'ἐλθέτω ἡ βασιλεία σου', 'elthetō hē basileia sou', 'G2064/G932', 'Thy kingdom come — petition for God''s reign to break into history in its fullness. Aorist imperative: a single decisive coming.', 3),
  (3, 'ἐπιούσιον', 'epiousion', 'G1967', 'Daily — a notoriously rare word (effectively only here and Matt 6:11). Likely "necessary for the coming day" or "for our existence." Simple dependence on God''s daily provision.', 4),
  (4, 'ἄφες ἡμῖν τὰς ἁμαρτίας', 'aphes hēmin tas hamartias', 'G863/G266', 'Forgive us our sins — where Matthew has "debts" (opheilēmata), Luke has hamartias (sins), the same root as opheilonti ("indebted") in the same verse. Forgiveness received conditions forgiveness given.', 5),
  (4, 'πειρασμόν', 'peirasmon', 'G3986', 'Temptation / testing — dual-sense word: moral temptation and eschatological trial. "Lead us not into" = do not allow us to enter circumstances beyond our capacity.', 6),
  (8, 'ἀναίδειαν', 'anaideian', 'G335', 'Importunity — shameless persistence, absence of bashful reluctance. The neighbour yields not out of friendship but because the asker refuses to give up. Prayer that persists prevails.', 7),
  (9, 'αἰτεῖτε... ζητεῖτε... κρούετε', 'aiteite... zēteite... krouete', 'G154/G2212/G2925', 'Ask, seek, knock — three present imperatives: keep asking, keep seeking, keep knocking. Progressive intensification; persistent prayer is normative, not exceptional.', 8),
  (11, 'ἰχθῦς... ὄφις', 'ichthys... ophis', 'G2486/G3789', 'Fish... serpent — a fish without scales could look snake-like in the Galilean hills. No earthly father swaps nourishment for something deadly; the heavenly Father is infinitely trustworthy.', 9),
  (13, 'πνεῦμα ἅγιον', 'pneuma hagion', 'G4151/G40', 'Holy Spirit — where Matt 7:11 has "good things," Luke specifies the supreme good: the Spirit himself. Luke''s distinctive emphasis on the Spirit as the greatest gift.', 10),
  (15, 'Βεελζεβοὺλ', 'Beelzeboul', 'G954', 'Beelzebub / Baal-Zebul — "lord of the dwelling" or mockingly "lord of flies" (Baal-Zebub, 2 Kgs 1:2). A title for Satan as prince of demons, deployed here to slander Jesus.', 11),
  (17, 'βασιλεία ἐφ᾽ ἑαυτὴν διαμερισθεῖσα', 'basileia eph'' heautēn diameristheisa', 'G932/G1266', 'Kingdom divided against itself — political logic dismantles the slander. If Satan were behind the exorcisms, he would be destroying his own dominion.', 12),
  (20, 'ἐν δακτύλῳ θεοῦ', 'en daktylō theou', 'G1147/G2316', 'By the finger of God — direct echo of Exod 8:19 (the magicians in Egypt). Jesus''s exorcisms are a new Exodus: liberation from the oppressor by direct divine action.', 13),
  (21, 'ἰσχυρός', 'ischyros', 'G2478', 'Strong man — Satan guarding his dominion. The guarded house is the fallen world; the goods are the souls held in bondage.', 14),
  (22, 'ἰσχυρότερος', 'ischyroteros', 'G2478', 'Stronger than he — comparative: a superior strongman has arrived. Christ binds Satan and plunders his house, distributing the spoils (cf. Isa 53:12; Col 2:15).', 15),
  (23, 'ὁ μὴ ὢν μετ᾽ ἐμοῦ', 'ho mē ōn met'' emou', 'G3326', 'He that is not with me — no neutral ground. Kingdom-conflict demands alignment; passivity equals opposition. Contrast with 9:50 (the non-hostile outsider is counted ally).', 16),
  (26, 'ἑπτὰ ἕτερα πνεύματα', 'hepta hetera pneumata', 'G2033', 'Seven other spirits — completeness of demonic re-occupation. An empty moral reform without positive filling by Christ leaves the house available for worse occupation.', 17),
  (27, 'μακαρία ἡ κοιλία', 'makaria hē koilia', 'G2836', 'Blessed is the womb — a common first-century female beatitude on a hero''s mother. Jesus redirects blessedness from biological kinship to spiritual reception.', 18),
  (28, 'οἱ ἀκούοντες τὸν λόγον καὶ φυλάσσοντες', 'hoi akouontes ton logon kai phylassontes', 'G191/G5442', 'They that hear the word and keep it — phylassō = to guard, preserve, observe. Same principle as 6:47-48 and 8:21: hearing + doing constitutes true blessedness.', 19),
  (29, 'γενεὰ πονηρά', 'genea ponēra', 'G1074/G4190', 'Evil generation — genea = the contemporary generation, not a race. Luke echoes Moses''s indictment (Deut 32:5) and anticipates Acts 2:40.', 20),
  (30, 'σημεῖον Ἰωνᾶ', 'sēmeion Iōna', 'G4592/G2495', 'Sign of Jonah — the preacher-from-death. Luke emphasises Jonah''s kerygmatic role (v.32) whereas Matt 12:40 emphasises three days in the fish. Luke''s accent: repentance at preaching.', 21),
  (31, 'βασίλισσα νότου', 'basilissa notou', 'G938/G3558', 'Queen of the south — Sheba. A Gentile woman sought Solomon''s wisdom from great distance; this generation refuses greater wisdom at arm''s reach.', 22),
  (34, 'ὁ ὀφθαλμός σου ἁπλοῦς', 'ho ophthalmos sou haplous', 'G3788/G573', 'Thine eye single — haplous = simple, single, uncomplicated, sincere. Hebraic idiom for integrity and generosity; the whole person illumined when the inner eye is rightly oriented.', 23),
  (38, 'οὐ πρῶτον ἐβαπτίσθη', 'ou prōton ebaptisthē', 'G907', 'Not first washed — ceremonial hand-washing before the meal, a rabbinic tradition-of-the-elders not commanded by Torah. The Pharisee''s astonishment reveals how tradition had become law.', 24),
  (39, 'τὸ ἔξωθεν... τὸ ἔσωθεν', 'to exōthen... to esōthen', 'G1855/G2081', 'The outside... the inside — vessel-metaphor applied to the person. External ritual cleanness is worthless if the interior is full of greed (harpagē) and wickedness (ponēria).', 25),
  (41, 'δότε ἐλεημοσύνην', 'dote eleēmosynēn', 'G1325/G1654', 'Give alms — the true internal purifier. Generosity expresses the clean heart; hoarding reveals the rapacious one. Luke''s consistent theme: possessions reveal the heart.', 26),
  (42, 'οὐαὶ ὑμῖν', 'ouai hymin', 'G3759', 'Woe to you — prophetic lament-curse. A sorrowful denunciation of judgment, not a vindictive curse. Six woes total in Luke 11, echoing Isa 5''s pattern.', 27),
  (42, 'τὴν κρίσιν καὶ τὴν ἀγάπην τοῦ θεοῦ', 'tēn krisin kai tēn agapēn tou theou', 'G2920/G26/G2316', 'Judgment and the love of God — the weighty matters of Torah (echoing Mic 6:8). Scrupulous tithing while neglecting justice and love is the classic perversion.', 28),
  (44, 'μνημεῖα τὰ ἄδηλα', 'mnēmeia ta adēla', 'G3419/G82', 'Graves which appear not — unmarked tombs that defile the unsuspecting who walk over them (Num 19:16). Hidden corruption in pious exterior — the most dangerous form.', 29),
  (46, 'φορτία δυσβάστακτα', 'phortia dysbastakta', 'G5413/G1419', 'Burdens grievous to be borne — rabbinic casuistry multiplying Torah into unliveable detail, while the lawyers themselves do not assist with a finger.', 30),
  (49, 'ἡ σοφία τοῦ θεοῦ', 'hē sophia tou theou', 'G4678/G2316', 'The wisdom of God — a periphrasis for God speaking. Jesus speaks as divine Wisdom personified (cf. Prov 8; Matt 11:19), warning of generational martyrdom.', 31),
  (52, 'τὴν κλεῖδα τῆς γνώσεως', 'tēn kleida tēs gnōseōs', 'G2807/G1108', 'The key of knowledge — true interpretation of Scripture that opens the way to God. The lawyers took away the key through interpretive obfuscation and neither entered themselves nor permitted others.', 32)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Luke' AND c.chapter_number = 11 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

